SELECT * FROM ( SELECT
FROM tb_pmb_plan_online_open a LEFT join tb_mbm_user b ON a.create_id = b.id LEFT join tb_mbm_company_list c ON a.company_id = c.id LEFT join tb_pmb_plan_list d ON a.plan_id = d.id WHERE 1=1
) tb ORDER BY id DESC

SELECT id ,order_id ,order_state ,order_state_host ,order_memo ,account_num ,open_comp_dttm ,open_tel_num ,create_date FROM tb_pmb_plan_order_state WHERE 1=1
AND order_id = #{orderId}
ORDER BY id DESC
